SELECT forecast_id, forecast_date, case_count, hospitalization, mortality_rate, location_id, forecast_source, confidence_level, forecast_notes, forecast_status
FROM forecasts
WHERE model_id = (SELECT model_id FROM models WHERE model_name = 'CEPH-Rtrend_covid');

SELECT f.forecast_id, f.forecast_date, al.access_date
FROM forecasts f
INNER JOIN access_logs al ON f.forecast_id = al.forecast_id;

SELECT forecast_id, forecast_date, case_count
FROM forecasts
WHERE location_id = 1 AND model_id = 1;

SELECT forecasts.forecast_id, locations.location_name
FROM forecasts
JOIN locations ON forecasts.location_id = locations.location_id;
